cat > /tmp/binlog_parser/Program.cs << 'EOF'
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild(args[0]);

Console.WriteLine("=== Build Result ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

Console.WriteLine("=== Projects ===");
var projects = build.FindChildrenRecursive<Project>();
foreach (var p in projects)
{
    Console.WriteLine($"  {p.Name}");
}
Console.WriteLine();

Console.WriteLine("=== All Errors ===");
var errors = build.FindChildrenRecursive<Error>();
foreach (var error in errors)
{
    var project = error.GetNearestParent<Project>();
    Console.WriteLine($"  [{project?.Name ?? "?"}] {error.Code}: {error.File}({error.LineNumber}): {error.Text}");
}
Console.WriteLine();

// Check what packages Services references
Console.WriteLine("=== PackageReference items ===");
var items = build.FindChildrenRecursive<Item>();
foreach (var item in items)
{
    if (item.Name == "PackageReference")
    {
        var project = item.GetNearestParent<Project>();
        Console.WriteLine($"  [{project?.Name ?? "?"}] {item.Text}");
    }
}
Console.WriteLine();

// Check for dependency failures
Console.WriteLine("=== Build Targets with errors in Api ===");
var targets = build.FindChildrenRecursive<Target>();
foreach (var t in targets)
{
    var project = t.GetNearestParent<Project>();
    if (project != null && project.Name.Contains("Api"))
    {
        var targetErrors = t.FindChildrenRecursive<Error>();
        if (targetErrors.Count > 0)
        {
            Console.WriteLine($"  Target: {t.Name}");
            foreach (var e in targetErrors)
                Console.WriteLine($"    {e.Code}: {e.Text}");
        }
    }
}

// Also check for MSB error about failed project references
Console.WriteLine();
Console.WriteLine("=== Messages containing 'previously failed' or 'dependency' ===");
var messages = build.FindChildrenRecursive<Message>();
foreach (var m in messages)
{
    if (m.Text != null && (m.Text.Contains("previously failed") || m.Text.Contains("was not found") ||
        m.Text.Contains("dependency failed")))
    {
        Console.WriteLine($"  {m.Text}");
    }
}
EOF
