using System;
using System.Linq;
using System.Reflection;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild(args[0]);

// Check ArchiveFile type members
var archiveFileType = typeof(ArchiveFile);
Console.WriteLine("=== ArchiveFile properties ===");
foreach (var prop in archiveFileType.GetProperties())
    Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name}");
Console.WriteLine("=== ArchiveFile fields ===");
foreach (var field in archiveFileType.GetFields(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  {field.FieldType.Name} {field.Name}");

Console.WriteLine();
Console.WriteLine("=== SourceFiles type ===");
var sfProp = build.GetType().GetProperty("SourceFiles");
if (sfProp != null)
{
    Console.WriteLine($"Type: {sfProp.PropertyType}");
    var sourceFiles = sfProp.GetValue(build);
    if (sourceFiles != null)
    {
        var sfType = sourceFiles.GetType();
        Console.WriteLine($"Actual type: {sfType}");
        // Check if it's IEnumerable
        if (sourceFiles is System.Collections.IEnumerable enumerable)
        {
            int count = 0;
            foreach (var item in enumerable)
            {
                count++;
                var itemType = item.GetType();
                if (count == 1)
                {
                    Console.WriteLine($"Item type: {itemType}");
                    foreach (var p in itemType.GetProperties())
                        Console.WriteLine($"  {p.Name}: {p.GetValue(item)}");
                }
                // Check for our source files
                var fullPathProp = itemType.GetProperty("FullPath");
                if (fullPathProp != null)
                {
                    var path = fullPathProp.GetValue(item)?.ToString() ?? "";
                    if (path.Contains("UserService") || path.Contains("Models.cs") || path.Contains("Program.cs"))
                    {
                        var textProp = itemType.GetProperty("Text");
                        Console.WriteLine($"\n--- {path} ---");
                        Console.WriteLine(textProp?.GetValue(item)?.ToString() ?? "(no text prop)");
                    }
                }
            }
            Console.WriteLine($"\nTotal source files: {count}");
        }
    }
}
EOF
