arguments.command:
cat > /tmp/binlog_parser/Program.cs << 'EOF'
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild(args[0]);

// Check if Core compiled successfully (look for its output)
Console.WriteLine("=== Core compilation ===");
var tasks = build.FindChildrenRecursive<Task>();
bool coreCompiled = false;
foreach (var task in tasks)
{
    if (task.Name == "Csc")
    {
        var project = task.GetNearestParent<Project>();
        if (project != null && project.Name.Contains("Core"))
        {
            coreCompiled = true;
            var errors = task.FindChildrenRecursive<Error>();
            Console.WriteLine($"Core compiled: errors={errors.Count}");
            break;
        }
    }
}
if (!coreCompiled)
    Console.WriteLine("Core Csc task not found");

// Double check Services errors with full context
Console.WriteLine();
Console.WriteLine("=== Full error details ===");
var allErrors = build.FindChildrenRecursive<Error>();
foreach (var error in allErrors)
{
    var project = error.GetNearestParent<Project>();
    var target = error.GetNearestParent<Target>();
    Console.WriteLine($"Project: {project?.Name}");
    Console.WriteLine($"Target: {target?.Name}");
    Console.WriteLine($"Code: {error.Code}");
    Console.WriteLine($"File: {error.File}");
    Console.WriteLine($"Line: {error.LineNumber}, Col: {error.ColumnNumber}");
    Console.WriteLine($"Message: {error.Text}");
    Console.WriteLine();
}

// Check if there's a "Build FAILED" message
Console.WriteLine("=== Build result messages ===");
var msgs = build.FindChildrenRecursive<Message>();
foreach (var m in msgs)
{
    if (m.Text != null && (m.Text.Contains("Build FAILED") || m.Text.Contains("Build succeeded") ||
        m.Text.Contains("Error(s)") || m.Text.Contains("Warning(s)")))
    {
        Console.WriteLine($"  {m.Text}");
    }
}
EOF
